impl VecI32 {
    fn swap(self, i: i32, j: i32) -> VecI32 {
        vec_i32_swap(self.handle, i, j)
        return self
    }

    fn extend(self, other: VecI32) -> VecI32 {
        vec_i32_extend(self.handle, other.handle)
        return self
    }

    fn append(self, x: i32) -> VecI32 {
        return self.push(x)
    }
}
